#!/usr/bin/env python3
"""
Kafka Cluster Administration Script

Uses kafka-python AdminClient to create topics, manage partitions,
and configure topic settings via command-line arguments.
"""

import argparse
import sys
import json
import time
from kafka.admin import (
    KafkaAdminClient,
    NewTopic,
    NewPartitions,
    ConfigResource,
    ConfigResourceType,
)
from kafka.errors import (
    TopicAlreadyExistsError,
    UnknownTopicOrPartitionError,
    KafkaError,
)
from kafka import KafkaConsumer


def create_admin_client(bootstrap_servers, security_protocol="PLAINTEXT",
                        sasl_mechanism=None, sasl_username=None,
                        sasl_password=None):
    """Create and return a KafkaAdminClient instance."""
    config = {
        "bootstrap_servers": bootstrap_servers,
        "security_protocol": security_protocol,
        "client_id": "kafka-admin-script",
        "request_timeout_ms": 30000,
    }

    if sasl_mechanism:
        config["sasl_mechanism"] = sasl_mechanism
    if sasl_username:
        config["sasl_plain_username"] = sasl_username
    if sasl_password:
        config["sasl_plain_password"] = sasl_password

    try:
        admin_client = KafkaAdminClient(**config)
        print(f"[OK] Connected to Kafka cluster at {bootstrap_servers}")
        return admin_client
    except KafkaError as e:
        print(f"[ERROR] Failed to connect to Kafka cluster: {e}")
        sys.exit(1)


def create_topics(admin_client, topics_config):
    """
    Create one or more topics.

    topics_config: list of dicts with keys:
        - name: topic name
        - partitions: number of partitions (default 1)
        - replication_factor: replication factor (default 1)
        - config: dict of topic-level configs (optional)
    """
    new_topics = []
    for topic_cfg in topics_config:
        name = topic_cfg["name"]
        partitions = topic_cfg.get("partitions", 1)
        replication_factor = topic_cfg.get("replication_factor", 1)
        config = topic_cfg.get("config", {})

        new_topic = NewTopic(
            name=name,
            num_partitions=partitions,
            replication_factor=replication_factor,
            topic_configs=config,
        )
        new_topics.append(new_topic)
        print(f"[INFO] Preparing topic '{name}' "
              f"(partitions={partitions}, replication_factor={replication_factor}, "
              f"config={config})")

    try:
        result = admin_client.create_topics(new_topics=new_topics, validate_only=False)
        print(f"[OK] Topic creation request submitted successfully")
        # Wait a moment for propagation
        time.sleep(1)
        for topic_cfg in topics_config:
            print(f"  -> Topic '{topic_cfg['name']}' created")
    except TopicAlreadyExistsError as e:
        print(f"[WARNING] One or more topics already exist: {e}")
    except KafkaError as e:
        print(f"[ERROR] Failed to create topics: {e}")
        raise


def delete_topics(admin_client, topic_names):
    """Delete one or more topics."""
    try:
        result = admin_client.delete_topics(topics=topic_names)
        print(f"[OK] Topic deletion request submitted for: {', '.join(topic_names)}")
        time.sleep(1)
        for name in topic_names:
            print(f"  -> Topic '{name}' deleted")
    except UnknownTopicOrPartitionError as e:
        print(f"[WARNING] One or more topics do not exist: {e}")
    except KafkaError as e:
        print(f"[ERROR] Failed to delete topics: {e}")
        raise


def list_topics(admin_client, bootstrap_servers):
    """List all topics in the cluster with their partition info."""
    try:
        # Use KafkaConsumer to get topic metadata
        consumer = KafkaConsumer(
            bootstrap_servers=bootstrap_servers,
            request_timeout_ms=10000,
        )
        topics = consumer.topics()
        topic_partitions = {}
        for topic in sorted(topics):
            partitions = consumer.partitions_for_topic(topic)
            topic_partitions[topic] = len(partitions) if partitions else 0

        consumer.close()

        print(f"\n{'='*60}")
        print(f"{'Topic Name':<40} {'Partitions':>10}")
        print(f"{'='*60}")
        for topic, num_partitions in sorted(topic_partitions.items()):
            print(f"{topic:<40} {num_partitions:>10}")
        print(f"{'='*60}")
        print(f"Total topics: {len(topic_partitions)}")
        return topic_partitions
    except KafkaError as e:
        print(f"[ERROR] Failed to list topics: {e}")
        raise


def describe_topics(admin_client, topic_names):
    """Describe one or more topics with detailed metadata."""
    try:
        topic_metadata = admin_client.describe_topics(topics=topic_names)
        for topic_info in topic_metadata:
            topic_name = topic_info.get("topic", "unknown")
            partitions = topic_info.get("partitions", [])
            is_internal = topic_info.get("is_internal", False)

            print(f"\n{'='*60}")
            print(f"Topic: {topic_name}")
            print(f"Internal: {is_internal}")
            print(f"Partitions: {len(partitions)}")
            print(f"{'-'*60}")
            print(f"{'Partition':<12} {'Leader':>8} {'Replicas':>20} {'ISR':>20}")
            print(f"{'-'*60}")

            for partition in partitions:
                partition_id = partition.get("partition", "?")
                leader = partition.get("leader", "?")
                replicas = partition.get("replicas", [])
                isr = partition.get("isr", [])
                print(f"{partition_id:<12} {leader:>8} {str(replicas):>20} {str(isr):>20}")

            print(f"{'='*60}")
        return topic_metadata
    except KafkaError as e:
        print(f"[ERROR] Failed to describe topics: {e}")
        raise


def add_partitions(admin_client, topic_partitions):
    """
    Add partitions to existing topics.

    topic_partitions: dict mapping topic name to new total partition count
    """
    new_partitions = {}
    for topic_name, total_count in topic_partitions.items():
        new_partitions[topic_name] = NewPartitions(total_count=total_count)
        print(f"[INFO] Setting partition count for '{topic_name}' to {total_count}")

    try:
        result = admin_client.create_partitions(
            topic_partitions=new_partitions,
            validate_only=False,
        )
        print(f"[OK] Partition update request submitted successfully")
        time.sleep(1)
        for topic_name, total_count in topic_partitions.items():
            print(f"  -> Topic '{topic_name}' now has {total_count} partitions")
    except KafkaError as e:
        print(f"[ERROR] Failed to add partitions: {e}")
        raise


def describe_topic_config(admin_client, topic_name):
    """Describe the configuration of a topic."""
    try:
        config_resource = ConfigResource(
            resource_type=ConfigResourceType.TOPIC,
            name=topic_name,
        )
        result = admin_client.describe_configs(config_resources=[config_resource])

        print(f"\n{'='*70}")
        print(f"Configuration for topic: {topic_name}")
        print(f"{'='*70}")
        print(f"{'Config Key':<45} {'Value':>25}")
        print(f"{'-'*70}")

        for config_entry in result:
            for key, value in config_entry.items():
                config_value = value.value if hasattr(value, 'value') else str(value)
                print(f"{key:<45} {str(config_value):>25}")

        print(f"{'='*70}")
        return result
    except KafkaError as e:
        print(f"[ERROR] Failed to describe topic config: {e}")
        raise


def alter_topic_config(admin_client, topic_name, config_dict):
    """
    Alter topic configuration.

    config_dict: dict of config key-value pairs to set
    """
    try:
        config_resource = ConfigResource(
            resource_type=ConfigResourceType.TOPIC,
            name=topic_name,
            configs=config_dict,
        )
        result = admin_client.alter_configs(config_resources=[config_resource])
        print(f"[OK] Configuration updated for topic '{topic_name}':")
        for key, value in config_dict.items():
            print(f"  -> {key} = {value}")
        return result
    except KafkaError as e:
        print(f"[ERROR] Failed to alter topic config: {e}")
        raise


def describe_cluster(admin_client):
    """Describe the Kafka cluster."""
    try:
        cluster_metadata = admin_client.describe_cluster()
        print(f"\n{'='*60}")
        print(f"Kafka Cluster Information")
        print(f"{'='*60}")

        controller = cluster_metadata.get("controller", {})
        brokers = cluster_metadata.get("brokers", [])
        cluster_id = cluster_metadata.get("cluster_id", "N/A")

        print(f"Cluster ID: {cluster_id}")
        print(f"Controller: {controller}")
        print(f"Brokers ({len(brokers)}):")
        print(f"{'-'*60}")
        print(f"{'Node ID':<12} {'Host':<30} {'Port':>8}")
        print(f"{'-'*60}")

        for broker in brokers:
            node_id = broker.nodeId if hasattr(broker, 'nodeId') else broker.get('nodeId', '?')
            host = broker.host if hasattr(broker, 'host') else broker.get('host', '?')
            port = broker.port if hasattr(broker, 'port') else broker.get('port', '?')
            print(f"{node_id:<12} {host:<30} {port:>8}")

        print(f"{'='*60}")
        return cluster_metadata
    except KafkaError as e:
        print(f"[ERROR] Failed to describe cluster: {e}")
        raise


def list_consumer_groups(admin_client):
    """List all consumer groups."""
    try:
        groups = admin_client.list_consumer_groups()
        print(f"\n{'='*60}")
        print(f"Consumer Groups")
        print(f"{'='*60}")
        print(f"{'Group ID':<40} {'Protocol Type':>18}")
        print(f"{'-'*60}")

        for group_id, protocol_type in groups:
            print(f"{group_id:<40} {protocol_type:>18}")

        print(f"{'='*60}")
        print(f"Total consumer groups: {len(groups)}")
        return groups
    except KafkaError as e:
        print(f"[ERROR] Failed to list consumer groups: {e}")
        raise


def describe_consumer_groups(admin_client, group_ids):
    """Describe consumer groups."""
    try:
        descriptions = admin_client.describe_consumer_groups(group_ids)
        for desc in descriptions:
            group_id = desc.group
            state = desc.state
            protocol = desc.protocol
            protocol_type = desc.protocol_type
            members = desc.members

            print(f"\n{'='*70}")
            print(f"Consumer Group: {group_id}")
            print(f"State: {state}")
            print(f"Protocol: {protocol}")
            print(f"Protocol Type: {protocol_type}")
            print(f"Members ({len(members)}):")
            print(f"{'-'*70}")

            for member in members:
                member_id = member.member_id
                client_id = member.client_id
                client_host = member.client_host
                print(f"  Member: {member_id}")
                print(f"    Client ID: {client_id}")
                print(f"    Client Host: {client_host}")

                if hasattr(member, 'member_assignment') and member.member_assignment:
                    assignment = member.member_assignment
                    if hasattr(assignment, 'assignment'):
                        for topic_partition in assignment.assignment:
                            print(f"    Assignment: {topic_partition}")

            print(f"{'='*70}")
        return descriptions
    except KafkaError as e:
        print(f"[ERROR] Failed to describe consumer groups: {e}")
        raise


def parse_config_string(config_str):
    """Parse a config string like 'key1=value1,key2=value2' into a dict."""
    config = {}
    if config_str:
        for pair in config_str.split(","):
            pair = pair.strip()
            if "=" in pair:
                key, value = pair.split("=", 1)
                config[key.strip()] = value.strip()
    return config


def parse_topic_config_json(json_str):
    """Parse a JSON string for topic configurations."""
    try:
        return json.loads(json_str)
    except json.JSONDecodeError as e:
        print(f"[ERROR] Invalid JSON: {e}")
        sys.exit(1)


def build_parser():
    """Build the argument parser."""
    parser = argparse.ArgumentParser(
        description="Kafka Cluster Administration Tool",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  # Create a topic
  %(prog)s --bootstrap-servers localhost:9092 create-topic --name my-topic --partitions 3 --replication-factor 1

  # Create a topic with custom config
  %(prog)s --bootstrap-servers localhost:9092 create-topic --name my-topic --partitions 6 --replication-factor 3 --config "retention.ms=86400000,cleanup.policy=compact"

  # Create multiple topics from JSON
  %(prog)s --bootstrap-servers localhost:9092 create-topics-json --json '[{"name":"t1","partitions":3,"replication_factor":1,"config":{"retention.ms":"86400000"}},{"name":"t2","partitions":6}]'

  # List all topics
  %(prog)s --bootstrap-servers localhost:9092 list-topics

  # Describe a topic
  %(prog)s --bootstrap-servers localhost:9092 describe-topic --name my-topic

  # Delete topics
  %(prog)s --bootstrap-servers localhost:9092 delete-topic --names my-topic another-topic

  # Add partitions
  %(prog)s --bootstrap-servers localhost:9092 add-partitions --name my-topic --total-partitions 12

  # Describe topic config
  %(prog)s --bootstrap-servers localhost:9092 describe-config --name my-topic

  # Alter topic config
  %(prog)s --bootstrap-servers localhost:9092 alter-config --name my-topic --config "retention.ms=172800000,max.message.bytes=2097152"

  # Describe cluster
  %(prog)s --bootstrap-servers localhost:9092 describe-cluster

  # List consumer groups
  %(prog)s --bootstrap-servers localhost:9092 list-consumer-groups

  # Describe consumer groups
  %(prog)s --bootstrap-servers localhost:9092 describe-consumer-group --group-ids my-group
        """,
    )

    # Global arguments
    parser.add_argument(
        "--bootstrap-servers",
        required=True,
        help="Comma-separated list of Kafka broker addresses (host:port)",
    )
    parser.add_argument(
        "--security-protocol",
        default="PLAINTEXT",
        choices=["PLAINTEXT", "SSL", "SASL_PLAINTEXT", "SASL_SSL"],
        help="Security protocol (default: PLAINTEXT)",
    )
    parser.add_argument(
        "--sasl-mechanism",
        default=None,
        help="SASL mechanism (e.g., PLAIN, SCRAM-SHA-256, SCRAM-SHA-512)",
    )
    parser.add_argument(
        "--sasl-username",
        default=None,
        help="SASL username",
    )
    parser.add_argument(
        "--sasl-password",
        default=None,
        help="SASL password",
    )

    subparsers = parser.add_subparsers(dest="command", help="Administration command")

    # Create topic
    create_parser = subparsers.add_parser("create-topic", help="Create a single topic")
    create_parser.add_argument("--name", required=True, help="Topic name")
    create_parser.add_argument(
        "--partitions", type=int, default=1, help="Number of partitions (default: 1)"
    )
    create_parser.add_argument(
        "--replication-factor",
        type=int,
        default=1,
        help="Replication factor (default: 1)",
    )
    create_parser.add_argument(
        "--config",
        default=None,
        help="Topic config as key=value pairs separated by commas "
             "(e.g., 'retention.ms=86400000,cleanup.policy=compact')",
    )

    # Create multiple topics from JSON
    create_json_parser = subparsers.add_parser(
        "create-topics-json", help="Create multiple topics from a JSON configuration"
    )
    create_json_parser.add_argument(
        "--json",
        required=True,
        help="JSON array of topic configurations",
    )
    create_json_parser.add_argument(
        "--file",
        default=None,
        help="Path to a JSON file with topic configurations (overrides --json)",
    )

    # List topics
    subparsers.add_parser("list-topics", help="List all topics")

    # Describe topic
    describe_parser = subparsers.add_parser("describe-topic", help="Describe topic(s)")
    describe_parser.add_argument(
        "--name", required=True, nargs="+", help="Topic name(s) to describe"
    )

    # Delete topic
    delete_parser = subparsers.add_parser("delete-topic", help="Delete topic(s)")
    delete_parser.add_argument(
        "--names", required=True, nargs="+", help="Topic name(s) to delete"
    )

    # Add partitions
    partitions_parser = subparsers.add_parser(
        "add-partitions", help="Increase the number of partitions for a topic"
    )
    partitions_parser.add_argument("--name", required=True, help="Topic name")
    partitions_parser.add_argument(
        "--total-partitions",
        type=int,
        required=True,
        help="New total number of partitions (must be greater than current)",
    )

    # Describe config
    desc_config_parser = subparsers.add_parser(
        "describe-config", help="Describe topic configuration"
    )
    desc_config_parser.add_argument("--name", required=True, help="Topic name")

    # Alter config
    alter_config_parser = subparsers.add_parser(
        "alter-config", help="Alter topic configuration"
    )
    alter_config_parser.add_argument("--name", required=True, help="Topic name")
    alter_config_parser.add_argument(
        "--config",
        required=True,
        help="Config key=value pairs separated by commas "
             "(e.g., 'retention.ms=172800000,max.message.bytes=2097152')",
    )

    # Describe cluster
    subparsers.add_parser("describe-cluster", help="Describe the Kafka cluster")

    # List consumer groups
    subparsers.add_parser("list-consumer-groups", help="List all consumer groups")

    # Describe consumer groups
    desc_group_parser = subparsers.add_parser(
        "describe-consumer-group", help="Describe consumer group(s)"
    )
    desc_group_parser.add_argument(
        "--group-ids", required=True, nargs="+", help="Consumer group ID(s)"
    )

    return parser


def main():
    parser = build_parser()
    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    bootstrap_servers = args.bootstrap_servers.split(",")

    admin_client = create_admin_client(
        bootstrap_servers=bootstrap_servers,
        security_protocol=args.security_protocol,
        sasl_mechanism=args.sasl_mechanism,
        sasl_username=args.sasl_username,
        sasl_password=args.sasl_password,
    )

    try:
        if args.command == "create-topic":
            config = parse_config_string(args.config) if args.config else {}
            topics_config = [
                {
                    "name": args.name,
                    "partitions": args.partitions,
                    "replication_factor": args.replication_factor,
                    "config": config,
                }
            ]
            create_topics(admin_client, topics_config)

        elif args.command == "create-topics-json":
            if args.file:
                with open(args.file, "r") as f:
                    topics_config = json.load(f)
            else:
                topics_config = parse_topic_config_json(args.json)

            if not isinstance(topics_config, list):
                print("[ERROR] JSON must be an array of topic configurations")
                sys.exit(1)

            create_topics(admin_client, topics_config)

        elif args.command == "list-topics":
            list_topics(admin_client, bootstrap_servers)

        elif args.command == "describe-topic":
            describe_topics(admin_client, args.name)

        elif args.command == "delete-topic":
            confirm = input(
                f"Are you sure you want to delete topics: {', '.join(args.names)}? (yes/no): "
            )
            if confirm.lower() == "yes":
                delete_topics(admin_client, args.names)
            else:
                print("[INFO] Deletion cancelled")

        elif args.command == "add-partitions":
            add_partitions(admin_client, {args.name: args.total_partitions})

        elif args.command == "describe-config":
            describe_topic_config(admin_client, args.name)

        elif args.command == "alter-config":
            config = parse_config_string(args.config)
            if not config:
                print("[ERROR] No valid config key-value pairs provided")
                sys.exit(1)
            alter_topic_config(admin_client, args.name, config)

        elif args.command == "describe-cluster":
            describe_cluster(admin_client)

        elif args.command == "list-consumer-groups":
            list_consumer_groups(admin_client)

        elif args.command == "describe-consumer-group":
            describe_consumer_groups(admin_client, args.group_ids)

        else:
            parser.print_help()

    except Exception as e:
        print(f"\n[FATAL] Unhandled error: {e}")
        sys.exit(1)
    finally:
        try:
            admin_client.close()
            print("\n[OK] Admin client connection closed")
        except Exception:
            pass


if __name__ == "__main__":
    main()